package org.example.service;
import org.example.model.dto.UserDto; import org.example.model.entity.User; import org.example.model.enums.UserRole; import org.example.repository.UserRepository; import org.junit.jupiter.api.Test; import org.junit.jupiter.api.extension.ExtendWith; import org.mockito.*; import org.mockito.junit.jupiter.MockitoExtension; import java.util.*; import static org.junit.jupiter.api.Assertions.*; import static org.mockito.ArgumentMatchers.any; import static org.mockito.Mockito.*;
@ExtendWith(MockitoExtension.class) class UserServiceTest { @Mock UserRepository repo; @InjectMocks UserService service; @Test void shouldCreateUser(){ UserDto dto=new UserDto(); dto.setName("Иван Иванов"); dto.setEmail("ivan@example.com"); dto.setRole(UserRole.ROLE_USER); User saved=new User(); saved.setId(1L); saved.setName(dto.getName()); saved.setEmail(dto.getEmail()); saved.setRole(UserRole.ROLE_USER); when(repo.save(any(User.class))).thenReturn(saved); User result=service.createUser(dto); assertNotNull(result); assertEquals(1L,result.getId()); assertEquals("Иван Иванов",result.getName()); verify(repo,times(1)).save(any(User.class)); } @Test void shouldReturnAllUsers(){ User u=new User(); u.setId(1L); u.setName("Иван"); when(repo.findAll()).thenReturn(List.of(u)); List<User> result=service.getAllUsers(); assertEquals(1,result.size()); assertEquals("Иван",result.get(0).getName()); } @Test void shouldThrowExceptionWhenUserNotFound(){ when(repo.findById(99L)).thenReturn(Optional.empty()); assertThrows(IllegalArgumentException.class,()->service.getUserById(99L)); } }
